('spanish:1-2-relationships-and-role-models:learn:a87ffca2', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'learn', 'mcq', 1, '{"readingTitle": "Who are the people in my life?", "reading": "<p>Core people vocabulary — tap 🔊 to hear each word.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la familia\">la familia</span></td><td>family</td><td><span data-say=\"los padres\">los padres</span></td><td>parents</td></tr>\n              <tr><td><span data-say=\"el hermano\">el hermano</span></td><td>brother</td><td><span data-say=\"la hermana\">la hermana</span></td><td>sister</td></tr>\n              <tr><td><span data-say=\"los abuelos\">los abuelos</span></td><td>grandparents</td><td><span data-say=\"el amigo\">el amigo / la amiga</span></td><td>friend</td></tr>\n              <tr><td><span data-say=\"el novio\">el novio / la novia</span></td><td>boyfriend / girlfriend</td><td><span data-say=\"el hijo\">el hijo / la hija</span></td><td>son / daughter</td></tr>\n            </table>\n            <p>Model: <span data-say=\"En mi familia hay cinco personas: mis padres, mis dos hermanos y yo.\">En mi familia hay cinco personas: mis padres, mis dos hermanos y yo.</span></p>", "question": "What does ‘los padres’ mean?", "options": ["parents", "grandparents", "godparents", "priests"]}'::jsonb, '{"answer": 0, "explain": "los padres = parents. los abuelos = grandparents."}'::jsonb),
('spanish:1-2-relationships-and-role-models:learn:beed28ac', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe someone''s personality?", "reading": "<p>Use <strong>ser</strong> (a permanent trait) + an adjective. The adjective must <strong>agree</strong>: change ‑o → ‑a for a female.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"simpático\">simpático / simpática</span></td><td>nice, friendly</td><td><span data-say=\"gracioso\">gracioso / graciosa</span></td><td>funny</td></tr>\n              <tr><td><span data-say=\"amable\">amable</span></td><td>kind</td><td><span data-say=\"hablador\">hablador / habladora</span></td><td>talkative</td></tr>\n              <tr><td><span data-say=\"cariñoso\">cariñoso / cariñosa</span></td><td>affectionate</td><td><span data-say=\"egoísta\">egoísta</span></td><td>selfish</td></tr>\n              <tr><td><span data-say=\"terco\">terco / terca</span></td><td>stubborn</td><td><span data-say=\"celoso\">celoso / celosa</span></td><td>jealous</td></tr>\n            </table>\n            <p><span data-say=\"Mi madre es muy cariñosa y mi hermano es gracioso.\">Mi madre es muy cariñosa y mi hermano es gracioso.</span> <em>(Note: cariños<strong>a</strong> for ‘madre’, gracios<strong>o</strong> for ‘hermano’.)</em></p>", "question": "How do you say ‘My sister is funny’?", "options": ["Mi hermana es graciosa", "Mi hermana es gracioso", "Mi hermana está graciosa", "Mi hermana es graciosos"]}'::jsonb, '{"answer": 0, "explain": "‘hermana’ is female → gracios­a; personality uses ser, not estar."}'::jsonb),
('spanish:1-2-relationships-and-role-models:learn:73f45641', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'learn', 'mcq', 1, '{"readingTitle": "How do I say I get on (or clash) with people?", "reading": "<p>The key phrase is the reflexive <strong>llevarse bien / mal con</strong> — to get on well / badly with:</p>\n            <ul>\n              <li><span data-say=\"Me llevo bien con mi madre.\">Me llevo bien con mi madre.</span> — I get on well with my mum.</li>\n              <li><span data-say=\"Me llevo mal con mi hermano.\">Me llevo mal con mi hermano.</span> — I get on badly with my brother.</li>\n            </ul>\n            <p>Other useful verbs:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"pelearse\">pelearse</span></td><td>to fight / argue</td><td><span data-say=\"apoyar\">apoyar</span></td><td>to support</td></tr>\n              <tr><td><span data-say=\"respetar\">respetar</span></td><td>to respect</td><td><span data-say=\"confiar en\">confiar en</span></td><td>to trust</td></tr>\n            </table>", "question": "‘Me llevo bien con mi madre’ means…", "options": ["I get on well with my mum", "I look exactly like my mother does", "I take my mum out a lot", "I carry my mum''s bags"]}'::jsonb, '{"answer": 0, "explain": "llevarse bien con = to get on well with. (Don’t translate ‘llevo’ literally as ‘I carry’.)"}'::jsonb),
('spanish:1-2-relationships-and-role-models:learn:b6c3a9f5', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'learn', 'mcq', 1, '{"readingTitle": "How do I compare people?", "reading": "<p>Use comparatives to make richer sentences:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"más… que\">más… que</span></td><td>more… than</td><td><span data-say=\"menos… que\">menos… que</span></td><td>less… than</td></tr>\n              <tr><td><span data-say=\"tan… como\">tan… como</span></td><td>as… as</td><td><span data-say=\"mejor / peor\">mejor / peor</span></td><td>better / worse</td></tr>\n            </table>\n            <p><span data-say=\"Mi hermana es más habladora que yo, pero yo soy más trabajador.\">Mi hermana es más habladora que yo, pero yo soy más trabajador.</span></p>\n            <p>Careful: ‘better’ is just <strong>mejor</strong> — never ‘más mejor’.</p>", "question": "How do you say ‘more talkative than me’?", "options": ["más habladora que yo", "más habladora de yo", "tan habladora que yo", "más mejor habladora"]}'::jsonb, '{"answer": 0, "explain": "‘more… than’ = más… que; ‘than me’ = que yo."}'::jsonb),
('spanish:1-2-relationships-and-role-models:learn:3e47c728', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about role models?", "reading": "<p>A role model is <span data-say=\"un modelo a seguir\">un modelo a seguir</span>. Say who and, crucially, <strong>why</strong>:</p>\n            <ul>\n              <li><span data-say=\"admirar\">admirar</span> — to admire; <span data-say=\"respetar\">respetar</span> — to respect</li>\n              <li><span data-say=\"trabajador\">trabajador / trabajadora</span> — hard-working; <span data-say=\"valiente\">valiente</span> — brave</li>\n            </ul>\n            <p><span data-say=\"Mi modelo a seguir es mi abuela porque es muy trabajadora y siempre me apoya.\">Mi modelo a seguir es mi abuela porque es muy trabajadora y siempre me apoya.</span></p>", "question": "What does ‘un modelo a seguir’ mean?", "options": ["a role model", "a fashion model", "a model railway", "a school subject"]}'::jsonb, '{"answer": 0, "explain": "un modelo a seguir = a role model (literally ‘a model to follow’)."}'::jsonb),
('spanish:1-2-relationships-and-role-models:learn:2a4e3d61', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'learn', 'mcq', 1, '{"readingTitle": "Higher: relatives and the imperfect", "reading": "<p><span class=\"tier-h\">H</span> Join ideas with relative pronouns and describe how things <em>used to be</em> with the imperfect:</p>\n            <ul>\n              <li><span data-say=\"que\">que</span> (who/that), <span data-say=\"quien\">quien</span> (who, after a preposition): <span data-say=\"Admiro a mi padre, que siempre me apoya.\">Admiro a mi padre, que siempre me apoya.</span> <span class=\"tier-h\">H</span></li>\n              <li>Imperfect for ‘used to’: <span data-say=\"De pequeño, me peleaba con mi hermano.\">De pequeño, me peleaba con mi hermano.</span> — When I was little, I used to fight with my brother. <span class=\"tier-h\">H</span></li>\n            </ul>", "question": "‘De pequeño, me peleaba con mi hermano’ means…", "options": ["When I was little, I used to fight with my brother", "As a young child, I am going to fight with my brother", "I fought with my little brother once", "My little brother fights with me now"]}'::jsonb, '{"answer": 0, "explain": "The imperfect ‘me peleaba’ = ‘I used to fight’; ‘de pequeño’ = when I was little."}'::jsonb),
('spanish:1-2-relationships-and-role-models:learn:ab50adaf', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'learn', 'mcq', 1, '{"readingTitle": "When things go wrong — conflict, secrets and forgiveness", "reading": "<p>Relationships aren''t always easy. More verbs and feelings for when things go wrong:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"romper con\">romper con</span></td><td>to break up with</td><td><span data-say=\"discutir\">discutir</span></td><td>to argue</td></tr>\n              <tr><td><span data-say=\"pegar\">pegar</span></td><td>to hit</td><td><span data-say=\"perdonar\">perdonar</span></td><td>to forgive</td></tr>\n              <tr><td><span data-say=\"un secreto\">un secreto</span></td><td>a secret</td><td><span data-say=\"una mentira\">una mentira</span></td><td>a lie</td></tr>\n              <tr><td><span data-say=\"la vergüenza\">la vergüenza</span></td><td>shame, embarrassment</td><td><span data-say=\"criticar\">criticar</span></td><td>to criticise</td></tr>\n            </table>\n            <p><span data-say=\"Estoy enojado porque mi amigo rompió con su novia y ahora se siente muy solo.\">Estoy enojado porque mi amigo rompió con su novia y ahora se siente muy solo.</span> = I am angry because my friend broke up with his girlfriend and now feels very lonely (<span data-say=\"la soledad\">la soledad</span> = loneliness). <span class=\"tier-h\">H</span> <span data-say=\"Desafortunadamente, no nos hablamos desde entonces.\">Desafortunadamente, no nos hablamos desde entonces.</span> = Unfortunately, we haven''t spoken since then.</p>", "question": "What does ‘romper con alguien’ mean?", "options": ["to break up with someone", "to make up with someone again", "to fall in love with someone", "to introduce someone to your family"]}'::jsonb, '{"answer": 0, "explain": "romper con = to break up with. Don''t confuse with hacer las paces (to make up) or enamorarse (to fall in love)."}'::jsonb),
('spanish:1-2-relationships-and-role-models:learn:447db90a', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'learn', 'mcq', 1, '{"readingTitle": "What makes a good role model? Personality, tolerance and feelings", "reading": "<p>More personality words for describing role models — and vocabulary for talking about identity with respect:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"independiente\">independiente</span></td><td>independent</td><td><span data-say=\"capaz\">capaz</span></td><td>capable</td></tr>\n              <tr><td><span data-say=\"sencillo\">sencillo / sencilla</span></td><td>down-to-earth, simple</td><td><span data-say=\"positivo\">positivo / positiva</span></td><td>positive</td></tr>\n              <tr><td><span data-say=\"excelente\">excelente</span></td><td>excellent</td><td><span data-say=\"fiel\">fiel</span></td><td>loyal, faithful</td></tr>\n              <tr><td><span data-say=\"comprensivo\">comprensivo / comprensiva</span></td><td>understanding</td><td><span data-say=\"tolerante\">tolerante</span></td><td>tolerant</td></tr>\n            </table>\n            <p><span data-say=\"Mi modelo a seguir es fiel, comprensiva y siempre positiva. Tiene mucho sentimiento y buen humor.\">Mi modelo a seguir es fiel, comprensiva y siempre positiva. Tiene mucho sentimiento y buen humor.</span> = My role model is loyal, understanding and always positive. She has a lot of feeling and a good sense of humour.</p>\n            <p>Being tolerant means respecting everyone: <span data-say=\"Es importante ser tolerante, sea la persona gay, heterosexual o transgénero.\">Es importante ser tolerante, sea la persona gay, heterosexual o transgénero.</span> = It''s important to be tolerant, whether the person is gay, heterosexual or transgender.</p>", "question": "What does ‘comprensivo’ mean?", "options": ["understanding", "complicated, hard to follow", "comprehensive, covering everything", "competitive, always wants to win"]}'::jsonb, '{"answer": 0, "explain": "comprensivo = understanding (a false friend — NOT ‘comprehensive’)."}'::jsonb),
('spanish:1-2-relationships-and-role-models:misc:6923c94c', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mi madre es simpático.</p><p><strong>✅ The correct idea:</strong> Mi madre es simpática.</p>", "question": "Why ‘simpática’ here?", "options": ["the adjective agrees with the female ‘madre’", "‘simpático’ has to be written in the plural", "you always use the masculine form as default", "the verb ‘ser’ forces an ‑o ending"]}'::jsonb, '{"answer": 0, "explain": "Adjectives agree in gender: madre is female → simpática."}'::jsonb),
